(function(){"use strict";(function(){const t=new URLSearchParams(window.location.search).get("shop");if(t){window.addEventListener("message",e=>{var s;((s=e.data)==null?void 0:s.type)==="SHOPAPPCHAT_GET_SHOP"&&e.source&&e.source.postMessage({type:"SHOPAPPCHAT_SHOP",shop:t},"*")});const o=()=>{document.querySelectorAll("iframe").forEach(e=>{try{e.contentWindow.postMessage({type:"SHOPAPPCHAT_SHOP",shop:t},"*")}catch{}})};document.readyState==="complete"?o():window.addEventListener("load",o)}})()})();
